const query = $('adjust_time').item.json.original_query;

// All calendar events returned from Google Calendar
const events = $input.all();

// Parse requested time as Philippine time
const requestedTime = new Date(query.replace(' ', 'T') + ':00+08:00');

// Extract the requested hour and minute
const requestedHour = requestedTime.getUTCHours();
const requestedMinute = requestedTime.getUTCMinutes();

// Build list of taken time slots from calendar events
const takenSlots = events
  .filter(item => item.json.status === 'confirmed')
  .map(item => new Date(item.json.start.dateTime).toISOString());

const suggestions = [];
let daysChecked = 0;

while (suggestions.length < 3 && daysChecked < 14) {
  daysChecked++;

  // Build candidate slot (next day, same time, in UTC)
  const candidate = new Date(requestedTime.getTime() + daysChecked * 24 * 60 * 60 * 1000);

  // Check day of week in Philippine time
  const dayOfWeek = new Date(candidate.toLocaleString('en-US', { 
    timeZone: 'Asia/Manila' 
  })).getDay(); // 0=Sun, 1=Mon, 2=Tue, 3=Wed, 4=Thu, 5=Fri, 6=Sat

  // Skip weekends
  if (dayOfWeek === 0 || dayOfWeek === 6) continue;

  // Get the hour in Philippine time
  const phHour = parseInt(new Date(candidate.toLocaleString('en-US', {
    timeZone: 'Asia/Manila'
  })).getHours());

  // Skip outside operating hours (before 10am or after 9pm)
  if (phHour < 10 || phHour > 21) continue;

  // Check if this slot is taken
  const isTaken = takenSlots.some(takenSlot => {
    const diff = Math.abs(new Date(takenSlot) - candidate);
    return diff < 2 * 60 * 60 * 1000; // within 2 hour window
  });

  if (isTaken) continue;

  // Format for display
  const displayDate = candidate.toLocaleString('en-PH', {
    timeZone: 'Asia/Manila',
    weekday: 'long',
    month: 'long',
    day: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    hour12: true
  });

  suggestions.push(displayDate);
}

return [{
  json: {
    result: "taken",
    suggestions: suggestions
  }
}];
